// OfflineTokenGenerator.js
import React, { useState, useEffect, useCallback, useRef } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  FlatList,
  StyleSheet,
  Alert,
  Platform,
} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import * as Crypto from 'expo-crypto';

// Secure random token generation using cryptographically secure APIs
const generateSecureRandomBytes = async (byteLength = 32) => {
  const randomBytes = await Crypto.getRandomBytesAsync(byteLength);
  const hexString = Array.from(randomBytes)
    .map((byte) => byte.toString(16).padStart(2, '0'))
    .join('');
  return hexString;
};

const generateSecureToken = async () => {
  const tokenId = await generateSecureRandomBytes(16);
  const tokenSecret = await generateSecureRandomBytes(32);
  const timestamp = Date.now();
  const nonce = await generateSecureRandomBytes(8);

  const tokenPayload = `${tokenId}.${timestamp}.${nonce}`;
  const digest = await Crypto.digestStringAsync(
    Crypto.CryptoDigestAlgorithm.SHA256,
    `${tokenPayload}.${tokenSecret}`
  );

  return {
    id: tokenId,
    token: `otk_${tokenId}_${digest.substring(0, 32)}`,
    secret: tokenSecret,
    nonce,
    createdAt: timestamp,
    expiresAt: timestamp + 24 * 60 * 60 * 1000, // 24 hours
    isOffline: true,
    platform: Platform.OS,
    synced: false,
  };
};

// Secure storage wrapper with key derivation
const SecureTokenStorage = {
  STORAGE_KEY_PREFIX: '@offline_tokens_',
  SESSION_KEY: '@offline_session_key',

  async _getSessionKey() {
    let sessionKey = await AsyncStorage.getItem(this.SESSION_KEY);
    if (!sessionKey) {
      sessionKey = await generateSecureRandomBytes(32);
      await AsyncStorage.setItem(this.SESSION_KEY, sessionKey);
    }
    return sessionKey;
  },

  async _deriveStorageKey(identifier) {
    const sessionKey = await this._getSessionKey();
    const derived = await Crypto.digestStringAsync(
      Crypto.CryptoDigestAlgorithm.SHA256,
      `${sessionKey}:${identifier}`
    );
    return `${this.STORAGE_KEY_PREFIX}${derived.substring(0, 16)}`;
  },

  async storeToken(token) {
    try {
      const existingTokens = await this.getAllTokens();
      existingTokens.push({
        ...token,
        secret: undefined, // Never persist the raw secret
        secretHash: await Crypto.digestStringAsync(
          Crypto.CryptoDigestAlgorithm.SHA256,
          token.secret
        ),
      });
      const storageKey = await this._deriveStorageKey('token_list');
      await AsyncStorage.setItem(storageKey, JSON.stringify(existingTokens));
      return true;
    } catch (error) {
      console.error('Failed to store token securely:', error);
      return false;
    }
  },

  async getAllTokens() {
    try {
      const storageKey = await this._deriveStorageKey('token_list');
      const data = await AsyncStorage.getItem(storageKey);
      if (!data) return [];
      const tokens = JSON.parse(data);
      // Filter out expired tokens
      const now = Date.now();
      return tokens.filter((t) => t.expiresAt > now);
    } catch (error) {
      console.error('Failed to retrieve tokens:', error);
      return [];
    }
  },

  async clearExpiredTokens() {
    try {
      const tokens = await this.getAllTokens(); // Already filters expired
      const storageKey = await this._deriveStorageKey('token_list');
      await AsyncStorage.setItem(storageKey, JSON.stringify(tokens));
      return tokens.length;
    } catch (error) {
      console.error('Failed to clear expired tokens:', error);
      return 0;
    }
  },

  async clearAllTokens() {
    try {
      const storageKey = await this._deriveStorageKey('token_list');
      await AsyncStorage.removeItem(storageKey);
      return true;
    } catch (error) {
      console.error('Failed to clear all tokens:', error);
      return false;
    }
  },

  async getTokenCount() {
    const tokens = await this.getAllTokens();
    return tokens.length;
  },
};

// Action tracker that uses offline tokens
const OfflineActionTracker = {
  ACTIONS_KEY: '@offline_actions_',

  async _getActionsKey() {
    const sessionKey = await SecureTokenStorage._getSessionKey();
    const derived = await Crypto.digestStringAsync(
      Crypto.CryptoDigestAlgorithm.SHA256,
      `${sessionKey}:actions`
    );
    return `${this.ACTIONS_KEY}${derived.substring(0, 16)}`;
  },

  async trackAction(tokenId, actionType, actionData = {}) {
    try {
      const actionNonce = await generateSecureRandomBytes(8);
      const timestamp = Date.now();

      const actionRecord = {
        actionId: await generateSecureRandomBytes(12),
        tokenId,
        actionType,
        actionData,
        timestamp,
        nonce: actionNonce,
        synced: false,
      };

      // Create integrity hash for the action
      const integrityPayload = JSON.stringify({
        actionId: actionRecord.actionId,
        tokenId: actionRecord.tokenId,
        actionType: actionRecord.actionType,
        timestamp: actionRecord.timestamp,
        nonce: actionRecord.nonce,
      });

      actionRecord.integrityHash = await Crypto.digestStringAsync(
        Crypto.CryptoDigestAlgorithm.SHA256,
        integrityPayload
      );

      const actionsKey = await this._getActionsKey();
      const existingData = await AsyncStorage.getItem(actionsKey);
      const actions = existingData ? JSON.parse(existingData) : [];
      actions.push(actionRecord);
      await AsyncStorage.setItem(actionsKey, JSON.stringify(actions));

      return actionRecord;
    } catch (error) {
      console.error('Failed to track action:', error);
      return null;
    }
  },

  async getActions() {
    try {
      const actionsKey = await this._getActionsKey();
      const data = await AsyncStorage.getItem(actionsKey);
      return data ? JSON.parse(data) : [];
    } catch (error) {
      console.error('Failed to get actions:', error);
      return [];
    }
  },

  async getUnsyncedActions() {
    const actions = await this.getActions();
    return actions.filter((a) => !a.synced);
  },

  async verifyActionIntegrity(action) {
    const integrityPayload = JSON.stringify({
      actionId: action.actionId,
      tokenId: action.tokenId,
      actionType: action.actionType,
      timestamp: action.timestamp,
      nonce: action.nonce,
    });

    const expectedHash = await Crypto.digestStringAsync(
      Crypto.CryptoDigestAlgorithm.SHA256,
      integrityPayload
    );

    return expectedHash === action.integrityHash;
  },

  async clearActions() {
    try {
      const actionsKey = await this._getActionsKey();
      await AsyncStorage.removeItem(actionsKey);
      return true;
    } catch (error) {
      return false;
    }
  },
};

// Main component
const OfflineTokenGenerator = () => {
  const [tokens, setTokens] = useState([]);
  const [actions, setActions] = useState([]);
  const [activeToken, setActiveToken] = useState(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isOffline, setIsOffline] = useState(true);
  const [tokenCount, setTokenCount] = useState(0);
  const cleanupIntervalRef = useRef(null);

  const loadTokens = useCallback(async () => {
    const storedTokens = await SecureTokenStorage.getAllTokens();
    setTokens(storedTokens);
    setTokenCount(storedTokens.length);

    const storedActions = await OfflineActionTracker.getActions();
    setActions(storedActions);

    if (storedTokens.length > 0 && !activeToken) {
      const latestValid = storedTokens.find((t) => t.expiresAt > Date.now());
      if (latestValid) {
        setActiveToken(latestValid);
      }
    }
  }, [activeToken]);

  useEffect(() => {
    loadTokens();

    // Periodic cleanup of expired tokens
    cleanupIntervalRef.current = setInterval(async () => {
      await SecureTokenStorage.clearExpiredTokens();
      await loadTokens();
    }, 60000); // Every minute

    return () => {
      if (cleanupIntervalRef.current) {
        clearInterval(cleanupIntervalRef.current);
      }
    };
  }, [loadTokens]);

  const handleGenerateToken = async () => {
    if (isGenerating) return;

    setIsGenerating(true);
    try {
      const MAX_TOKENS = 50;
      if (tokenCount >= MAX_TOKENS) {
        Alert.alert(
          'Token Limit Reached',
          `Maximum of ${MAX_TOKENS} active tokens allowed. Please sync or clear old tokens.`
        );
        return;
      }

      const newToken = await generateSecureToken();
      const stored = await SecureTokenStorage.storeToken(newToken);

      if (stored) {
        setActiveToken(newToken);
        await loadTokens();

        // Track the token generation action
        await OfflineActionTracker.trackAction(
          newToken.id,
          'TOKEN_GENERATED',
          {
            platform: Platform.OS,
            isOffline,
          }
        );
        await loadTokens();
      } else {
        Alert.alert('Error', 'Failed to store token securely.');
      }
    } catch (error) {
      console.error('Token generation failed:', error);
      Alert.alert('Error', 'Failed to generate secure token.');
    } finally {
      setIsGenerating(false);
    }
  };

  const handleTrackAction = async (actionType) => {
    if (!activeToken) {
      Alert.alert('No Active Token', 'Please generate a token first.');
      return;
    }

    const action = await OfflineActionTracker.trackAction(
      activeToken.id,
      actionType,
      {
        timestamp: Date.now(),
        platform: Platform.OS,
      }
    );

    if (action) {
      await loadTokens();
    }
  };

  const handleVerifyIntegrity = async () => {
    const allActions = await OfflineActionTracker.getActions();
    let validCount = 0;
    let invalidCount = 0;

    for (const action of allActions) {
      const isValid = await OfflineActionTracker.verifyActionIntegrity(action);
      if (isValid) {
        validCount++;
      } else {
        invalidCount++;
      }
    }

    Alert.alert(
      'Integrity Check',
      `Valid: ${validCount}\nInvalid: ${invalidCount}\nTotal: ${allActions.length}`
    );
  };

  const handleClearAll = async () => {
    Alert.alert(
      'Clear All Data',
      'This will remove all tokens and tracked actions. Continue?',
      [
        { text: 'Cancel', style: 'cancel' },
        {
          text: 'Clear',
          style: 'destructive',
          onPress: async () => {
            await SecureTokenStorage.clearAllTokens();
            await OfflineActionTracker.clearActions();
            setActiveToken(null);
            setTokens([]);
            setActions([]);
            setTokenCount(0);
          },
        },
      ]
    );
  };

  const formatTimestamp = (ts) => {
    return new Date(ts).toLocaleString();
  };

  const getTimeRemaining = (expiresAt) => {
    const remaining = expiresAt - Date.now();
    if (remaining <= 0) return 'Expired';
    const hours = Math.floor(remaining / (1000 * 60 * 60));
    const minutes = Math.floor((remaining % (1000 * 60 * 60)) / (1000 * 60));
    return `${hours}h ${minutes}m`;
  };

  const renderTokenItem = ({ item }) => (
    <View style={[styles.tokenItem, item.id === activeToken?.id && styles.activeTokenItem]}>
      <View style={styles.tokenHeader}>
        <Text style={styles.tokenLabel}>
          {item.id === activeToken?.id ? '● Active' : '○ Inactive'}
        </Text>
        <Text style={styles.tokenExpiry}>
          {getTimeRemaining(item.expiresAt)}
        </Text>
      </View>
      <Text style={styles.tokenText} numberOfLines={1} ellipsizeMode="middle">
        {item.token}
      </Text>
      <Text style={styles.tokenMeta}>
        Created: {formatTimestamp(item.createdAt)} | {item.platform}
      </Text>
      {item.id !== activeToken?.id && (
        <TouchableOpacity
          style={styles.activateButton}
          onPress={() => setActiveToken(item)}
        >
          <Text style={styles.activateButtonText}>Set Active</Text>
        </TouchableOpacity>
      )}
    </View>
  );

  const renderActionItem = ({ item }) => (
    <View style={styles.actionItem}>
      <View style={styles.actionHeader}>
        <Text style={styles.actionType}>{item.actionType}</Text>
        <Text style={[styles.syncStatus, item.synced ? styles.synced : styles.unsynced]}>
          {item.synced ? 'Synced' : 'Pending'}
        </Text>
      </View>
      <Text style={styles.actionMeta}>
        Token: {item.tokenId?.substring(0, 12)}...
      </Text>
      <Text style={styles.actionMeta}>
        {formatTimestamp(item.timestamp)}
      </Text>
    </View>
  );

  return (
    <View style={styles.container}>
      <View style={styles.header}>
        <Text style={styles.title}>Offline Token Manager</Text>
        <View style={[styles.statusBadge, isOffline ? styles.offlineBadge : styles.onlineBadge]}>
          <Text style={styles.statusText}>
            {isOffline ? '⚡ Offline' : '🌐 Online'}
          </Text>
        </View>
      </View>

      <TouchableOpacity
        style={styles.toggleButton}
        onPress={() => setIsOffline(!isOffline)}
      >
        <Text style={styles.toggleButtonText}>
          Simulate {isOffline ? 'Online' : 'Offline'} Mode
        </Text>
      </TouchableOpacity>

      {/* Active Token Display */}
      {activeToken && (
        <View style={styles.activeTokenDisplay}>
          <Text style={styles.activeTokenLabel}>Active Session Token</Text>
          <Text style={styles.activeTokenValue} numberOfLines={1} ellipsizeMode="middle">
            {activeToken.token}
          </Text>
          <Text style={styles.activeTokenMeta}>
            Expires in: {getTimeRemaining(activeToken.expiresAt)}
          </Text>
        </View>
      )}

      {/* Action Buttons */}
      <View style={styles.buttonRow}>
        <TouchableOpacity
          style={[styles.generateButton, isGenerating && styles.disabledButton]}
          onPress={handleGenerateToken}
          disabled={isGenerating}
        >
          <Text style={styles.buttonText}>
            {isGenerating ? 'Generating...' : '🔑 New Token'}
          </Text>
        </TouchableOpacity>

        <TouchableOpacity
          style={styles.verifyButton}
          onPress={handleVerifyIntegrity}
        >
          <Text style={styles.buttonText}>🔍 Verify</Text>
        </TouchableOpacity>

        <TouchableOpacity
          style={styles.clearButton}
          onPress={handleClearAll}
        >
          <Text style={styles.buttonText}>🗑️ Clear</Text>
        </TouchableOpacity>
      </View>

      {/* Track Actions */}
      <View style={styles.section}>
        <Text style={styles.sectionTitle}>Track Actions</Text>
        <View style={styles.actionButtonRow}>
          {['PAGE_VIEW', 'FORM_SUBMIT', 'DATA_SAVE', 'USER_INPUT'].map(
            (actionType) => (
              <TouchableOpacity
                key={actionType}
                style={styles.actionButton}
                onPress={() => handleTrackAction(actionType)}
              >
                <Text style={styles.actionButtonText}>
                  {actionType.replace('_', ' ')}
                </Text>
              </TouchableOpacity>
            )
          )}
        </View>
      </View>

      {/* Stats */}
      <View style={styles.statsRow}>
        <View style={styles.statItem}>
          <Text style={styles.statValue}>{tokenCount}</Text>
          <Text style={styles.statLabel}>Tokens</Text>
        </View>
        <View style={styles.statItem}>
          <Text style={styles.statValue}>{actions.length}</Text>
          <Text style={styles.statLabel}>Actions</Text>
        </View>
        <View style={styles.statItem}>
          <Text style={styles.statValue}>
            {actions.filter((a) => !a.synced).length}
          </Text>
          <Text style={styles.statLabel}>Pending</Text>
        </View>
      </View>

      {/* Tokens List */}
      <View style={styles.section}>
        <Text style={styles.sectionTitle}>
          Session Tokens ({tokens.length})
        </Text>
        <FlatList
          data={tokens}
          renderItem={renderTokenItem}
          keyExtractor={(item) => item.id}
          style={styles.list}
          ListEmptyComponent={
            <Text style={styles.emptyText}>
              No tokens generated yet. Tap "New Token" to create one.
            </Text>
          }
        />
      </View>

      {/* Actions List */}
      <View style={styles.section}>
        <Text style={styles.sectionTitle}>
          Tracked Actions ({actions.length})
        </Text>
        <FlatList
          data={actions.slice(-10).reverse()}
          renderItem={renderActionItem}
          keyExtractor={(item) => item.actionId}
          style={styles.list}
          ListEmptyComponent={
            <Text style={styles.emptyText}>No actions tracked yet.</Text>
          }
        />
      </View>
    </View>
  );
};

